import React from 'react';
import { useLocation } from 'react-router-dom';
import { useWishlist } from '../context/WishlistContext';

export default function Snackbar() {
  const { totalItems, setIsDrawerOpen } = useWishlist();
  const location = useLocation();

  if (totalItems === 0 || location.pathname === '/wishlist') return null;

  return (
    <div className="fixed bottom-20 md:bottom-6 left-1/2 -translate-x-1/2 z-50 bg-surface-container-highest text-on-surface rounded-xl shadow-lg px-4 py-3 flex items-center gap-4 w-[90%] max-w-sm justify-between animate-fade-in">
      <div className="flex items-center gap-2">
        <span className="material-symbols-outlined text-primary">shopping_bag</span>
        <span className="text-body-sm font-semibold">{totalItems} item{totalItems > 1 ? 's' : ''} in cart</span>
      </div>
      <button 
        onClick={() => setIsDrawerOpen(true)}
        className="text-label-sm font-bold text-primary hover:text-primary-container uppercase"
      >
        View
      </button>
    </div>
  );
}
